#include <stdio.h>

int rowWithMax1s(int** mat, int n, int m) {
    int cnt_max = 0;
    int index = -1;
    for (int i = 0; i < n; i++) {
        int cnt_ones = 0;
        for (int j = 0; j < m; j++) {
            cnt_ones += mat[i][j];
        }
        if (cnt_ones > cnt_max) {
            cnt_max = cnt_ones;
            index = i;
        }
    }
    return index;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int** mat = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        mat[i] = (int*)malloc(m * sizeof(int));
        for (int j = 0; j < m; j++) {
            scanf("%d", &mat[i][j]);
        }
    }
    printf("%d\n", rowWithMax1s(mat, n, m));
    return 0;
}

